-- Migration 034: Alert title and description translation keys
--
-- Adds i18n keys for all alert messages generated by alerts.py.
-- Descriptions use {param} placeholders filled in by i18n.js at runtime.

INSERT INTO translation_keys (key, default_value, category, description) VALUES

-- Biennial currency (SFCL.160a)
('logbook.alert.currency_ok.title',    'Current biennial practice — SPL',       'logbook.alert', NULL),
('logbook.alert.currency_ok.desc',     '{time} and {launches} launches in the last 24 months — requirements met.', 'logbook.alert', NULL),
('logbook.alert.currency_low.title',   'Biennial currency low — SPL',            'logbook.alert', NULL),
('logbook.alert.currency_low.desc',    'SFCL.160(a) requires 5h + 15 launches in any 24-month window. Still needed: {missing}.', 'logbook.alert', NULL),

-- Launch method recency (SFCL.130) — generic keys, {method} substituted at runtime
('logbook.alert.launch_90.title',      'No {method} launch in over 90 days',     'logbook.alert', NULL),
('logbook.alert.launch_90.desc',       'Last {method} launch was {days} days ago. Consider a currency flight.', 'logbook.alert', NULL),
('logbook.alert.launch_180.title',     'No {method} launch in over 180 days',    'logbook.alert', NULL),
('logbook.alert.launch_180.desc',      'SFCL.130: privileges are restricted to methods passed in the practical exam. Last {method} launch was {days} days ago — refresher training recommended.', 'logbook.alert', NULL),

-- Passenger recency (FCL.060)
('logbook.alert.pax_recency.title',    'Recent experience — passenger carriage', 'logbook.alert', NULL),
('logbook.alert.pax_recency.desc',     'FCL.060: before carrying a passenger you need 3 take-offs and 3 landings as PIC in the last 90 days. Current: {flights} flights in the last 90 days.', 'logbook.alert', NULL),

-- Passenger thresholds (SFCL.115b)
('logbook.alert.pax_threshold_1.title','Passenger carriage — threshold 1',       'logbook.alert', NULL),
('logbook.alert.pax_threshold_1.desc', 'SFCL.115(b)(1): first passenger requires 10h PIC or 30 PIC launches. Current: {launches} PIC launches.', 'logbook.alert', NULL),
('logbook.alert.pax_threshold_2.title','Hire/reward flights — threshold 2',      'logbook.alert', NULL),
('logbook.alert.pax_threshold_2.desc', 'SFCL.115(b)(2): flights for hire/reward require 75h PIC or 200 PIC launches + proficiency check. Current: {launches} PIC launches.', 'logbook.alert', NULL),

-- Medical (Part-MED)
('logbook.alert.medical_missing.title','Medical certificate — no expiry date',   'logbook.alert', NULL),
('logbook.alert.medical_missing.desc', 'Enter your medical certificate expiry date in Settings so the system can remind you 60 days before it expires.', 'logbook.alert', NULL),
('logbook.alert.medical_expired.title','Medical certificate expired',             'logbook.alert', NULL),
('logbook.alert.medical_expired.desc', 'Your medical certificate expired {days} days ago. You cannot exercise the privileges of your licence until you renew it.', 'logbook.alert', NULL),
('logbook.alert.medical_soon.title',   'Medical certificate expiring soon',       'logbook.alert', NULL),
('logbook.alert.medical_soon.desc',    'Your medical certificate expires in {days} days ({expiry}). Schedule a renewal appointment.', 'logbook.alert', NULL),

-- Profile completeness
('logbook.alert.profile_license_date.title','SPL licence date not entered',      'logbook.alert', NULL),
('logbook.alert.profile_license_date.desc', 'Enter your SPL licence issue date in Settings. This is needed to accurately compute passenger-carriage thresholds (SFCL.115).', 'logbook.alert', NULL)

ON CONFLICT (key) DO NOTHING;


