('logbook.alert.medical_missing.title','Brak daty ważności orzeczenia lekarskiego'),
('logbook.alert.medical_missing.desc', 'Wprowadź datę ważności orzeczenia lekarskiego w Ustawieniach, aby system mógł przypominać 60 dni przed wygaśnięciem.'),
('logbook.alert.medical_expired.title','Orzeczenie lekarskie wygasło'),
('logbook.alert.medical_expired.desc', 'Twoje orzeczenie lekarskie wygasło {days} dni temu. Nie możesz korzystać z uprawnień licencji do czasu odnowienia.'),
('logbook.alert.medical_soon.title',   'Orzeczenie lekarskie wkrótce wygasa'),
('logbook.alert.medical_soon.desc',    'Twoje orzeczenie lekarskie wygasa za {days} dni ({expiry}). Zaplanuj wizytę odnowieniową.'),

('logbook.alert.profile_license_date.title','Nie podano daty uzyskania licencji SPL'),
('logbook.alert.profile_license_date.desc', 'Wprowadź datę uzyskania licencji SPL w Ustawieniach. Jest ona potrzebna do obliczenia progów dla lotów z pasażerami (SFCL.115).')

) AS t(k, v)
JOIN translation_keys ON translation_keys.key = t.k
ON CONFLICT (key_id, language_code) DO UPDATE SET value = EXCLUDED.value;


